('d3000000-0003-0000-0000-000000000001', 'd3000000-0001-0000-0000-000000000001', 'description', 'STRING', 'Fondé par Suge Knight et Dr. Dre en 1991 à Los Angeles. Le label le plus influent du Gangsta Rap et du G-Funk. A lancé Tupac, Snoop Dogg et Dr. Dre', NULL, NULL),
('d3000000-0003-0000-0000-000000000002', 'd3000000-0001-0000-0000-000000000001', 'fondateur', 'STRING', 'Suge Knight, Dr. Dre', NULL, NULL),
('d3000000-0003-0000-0000-000000000003', 'd3000000-0001-0000-0000-000000000001', 'annee_creation', 'STRING', '1991', NULL, NULL),
('d3000000-0003-0000-0000-000000000004', 'd3000000-0001-0000-0000-000000000001', 'ville', 'STRING', 'Los Angeles, Californie', NULL, NULL),
('d3000000-0003-0000-0000-000000000005', 'd3000000-0001-0000-0000-000000000002', 'description', 'STRING', 'Fondé par Jay-Z, Damon Dash et Kareem Biggs en 1994. A défini le rap new-yorkais des années 2000 et lancé la carrière de Kanye West', NULL, NULL),
('d3000000-0003-0000-0000-000000000006', 'd3000000-0001-0000-0000-000000000002', 'fondateur', 'STRING', 'Jay-Z, Damon Dash, Kareem Biggs', NULL, NULL),
('d3000000-0003-0000-0000-000000000007', 'd3000000-0001-0000-0000-000000000002', 'annee_creation', 'STRING', '1994', NULL, NULL),
('d3000000-0003-0000-0000-000000000008', 'd3000000-0001-0000-0000-000000000002', 'ville', 'STRING', 'New York', NULL, NULL),
('d3000000-0003-0000-0000-000000000009', 'd3000000-0001-0000-0000-000000000003', 'description', 'STRING', 'Fondé par Anthony Tiffith en 1991 à Compton. Label de Kendrick Lamar, SZA, Ab-Soul et ScHoolboy Q. Symbole du rap conscient de la nouvelle génération', NULL, NULL),
('d3000000-0003-0000-0000-000000000010', 'd3000000-0001-0000-0000-000000000003', 'fondateur', 'STRING', 'Anthony Tiffith (Top Dawg)', NULL, NULL),
('d3000000-0003-0000-0000-000000000011', 'd3000000-0001-0000-0000-000000000003', 'annee_creation', 'STRING', '1991', NULL, NULL),
('d3000000-0003-0000-0000-000000000012', 'd3000000-0001-0000-0000-000000000003', 'ville', 'STRING', 'Compton, Californie', NULL, NULL),
('d3000000-0003-0000-0000-000000000013', 'd3000000-0001-0000-0000-000000000004', 'description', 'STRING', 'Label de Drake fondé en 2012 à Toronto. A imposé le son de Toronto sur la scène rap mondiale et popularisé le R&B alternatif avec des artistes comme PartyNextDoor et Majid Jordan', NULL, NULL),
('d3000000-0003-0000-0000-000000000014', 'd3000000-0001-0000-0000-000000000004', 'fondateur', 'STRING', 'Drake, Oliver El-Khatib', NULL, NULL),
('d3000000-0003-0000-0000-000000000015', 'd3000000-0001-0000-0000-000000000004', 'annee_creation', 'STRING', '2012', NULL, NULL),
('d3000000-0003-0000-0000-000000000016', 'd3000000-0001-0000-0000-000000000004', 'ville', 'STRING', 'Toronto, Canada', NULL, NULL),
('d3000000-0003-0000-0000-000000000017', 'd3000000-0001-0000-0000-000000000005', 'description', 'STRING', 'Fondé par Rick Rubin et Russell Simmons en 1983. Premier grand label de rap, a signé LL Cool J, Public Enemy, Run-DMC et les Beastie Boys', NULL, NULL),
('d3000000-0003-0000-0000-000000000018', 'd3000000-0001-0000-0000-000000000005', 'fondateur', 'STRING', 'Rick Rubin, Russell Simmons', NULL, NULL),
('d3000000-0003-0000-0000-000000000019', 'd3000000-0001-0000-0000-000000000005', 'annee_creation', 'STRING', '1983', NULL, NULL),
('d3000000-0003-0000-0000-000000000020', 'd3000000-0001-0000-0000-000000000006', 'description', 'STRING', 'Fondé par Puff Daddy en 1993 à New York. Label du Notorious B.I.G. et symbole du rap East Coast dans sa rivalité avec Death Row', NULL, NULL),
('d3000000-0003-0000-0000-000000000021', 'd3000000-0001-0000-0000-000000000006', 'fondateur', 'STRING', 'Sean Combs (Puff Daddy)', NULL, NULL),
('d3000000-0003-0000-0000-000000000022', 'd3000000-0001-0000-0000-000000000006', 'annee_creation', 'STRING', '1993', NULL, NULL),
('d3000000-0003-0000-0000-000000000023', 'd3000000-0001-0000-0000-000000000007', 'description', 'STRING', 'Fondé par Birdman et Slim en 1991 à La Nouvelle-Orléans. Label de Lil Wayne et Nicki Minaj. A dominé le rap des années 2000 avec le son du Sud', NULL, NULL),
('d3000000-0003-0000-0000-000000000024', 'd3000000-0001-0000-0000-000000000007', 'fondateur', 'STRING', 'Birdman, Slim', NULL, NULL),
('d3000000-0003-0000-0000-000000000025', 'd3000000-0001-0000-0000-000000000007', 'annee_creation', 'STRING', '1991', NULL, NULL),
('d3000000-0003-0000-0000-000000000026', 'd3000000-0001-0000-0000-000000000008', 'description', 'STRING', 'Fondé par Dr. Dre en 1996. Label d''Eminem et 50 Cent. A perpétué l''héritage de Death Row avec un son plus produit et cinématographique', NULL, NULL),
('d3000000-0003-0000-0000-000000000027', 'd3000000-0001-0000-0000-000000000008', 'fondateur', 'STRING', 'Dr. Dre', NULL, NULL),
('d3000000-0003-0000-0000-000000000028', 'd3000000-0001-0000-0000-000000000010', 'description', 'STRING', 'Fondé par Coach K et Pierre Thomas en 2013 à Atlanta. Label des Migos, Lil Baby et City Girls. A défini le son Trap de la nouvelle génération', NULL, NULL),
('d3000000-0003-0000-0000-000000000029', 'd3000000-0001-0000-0000-000000000010', 'fondateur', 'STRING', 'Coach K, Pierre Thomas', NULL, NULL),
('d3000000-0003-0000-0000-000000000030', 'd3000000-0001-0000-0000-000000000010', 'annee_creation', 'STRING', '2013', NULL, NULL);
